using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

public class TicketPredictRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public class PredictResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

public class EvaluationResponse
{
    public double MacroAccuracy { get; set; }
    public double MicroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
    public IReadOnlyList<CategoryMetric> PerCategory { get; set; } = [];
}

public class CategoryMetric
{
    public string Category { get; set; } = string.Empty;
    public double Precision { get; set; }
    public double Recall { get; set; }
    public double F1Score { get; set; }
}

using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly string _dataPath;
    private readonly string _modelPath;
    private readonly Lock _modelLock = new();
    private ITransformer? _model;
    private PredictionEngine<TicketData, TicketPrediction>? _predictionEngine;
    private string[] _categoryLabels = [];

    public TicketClassifierService(IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 42);
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public EvaluationResponse TrainAndEvaluate()
    {
        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(dataView, testFraction: 0.3, seed: 42);

        var pipeline = _mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category)))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue(
                "PredictedLabel", "PredictedLabel"));

        // Train on the full dataset so the model has all examples
        var model = pipeline.Fit(dataView);

        // Evaluate using cross-validation for more reliable metrics on small datasets
        var cvResults = _mlContext.MulticlassClassification.CrossValidate(
            dataView, pipeline, numberOfFolds: 3, labelColumnName: "Label");

        var avgMetrics = new MulticlassClassificationMetrics[] { };
        var bestRun = cvResults.OrderByDescending(r => r.Metrics.MacroAccuracy).First();
        var metrics = bestRun.Metrics;

        lock (_modelLock)
        {
            _model = model;
            _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(model);
            _mlContext.Model.Save(model, dataView.Schema, _modelPath);

            // Extract the category labels from the trained model's key-to-value mapping
            var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
            var labelColumn = model.GetOutputSchema(dataView.Schema)["Label"];
            labelColumn.GetKeyValues(ref labelBuffer);
            _categoryLabels = labelBuffer.DenseValues().Select(v => v.ToString()).ToArray();
        }

        var response = new EvaluationResponse
        {
            MacroAccuracy = metrics.MacroAccuracy,
            MicroAccuracy = metrics.MicroAccuracy,
            LogLoss = metrics.LogLoss,
            LogLossReduction = metrics.LogLossReduction,
            PerCategory = metrics.PerClassLogLoss
                .Select((logLoss, i) => new CategoryMetric
                {
                    Category = i < _categoryLabels.Length ? _categoryLabels[i] : $"Class {i}",
                    F1Score = i < metrics.ConfusionMatrix.PerClassRecall.Count
                        ? 2 * metrics.ConfusionMatrix.PerClassPrecision[i]
                              * metrics.ConfusionMatrix.PerClassRecall[i]
                              / (metrics.ConfusionMatrix.PerClassPrecision[i]
                                 + metrics.ConfusionMatrix.PerClassRecall[i] + 1e-10)
                        : 0,
                    Precision = i < metrics.ConfusionMatrix.PerClassPrecision.Count
                        ? metrics.ConfusionMatrix.PerClassPrecision[i] : 0,
                    Recall = i < metrics.ConfusionMatrix.PerClassRecall.Count
                        ? metrics.ConfusionMatrix.PerClassRecall[i] : 0,
                })
                .ToList()
        };

        return response;
    }

    public PredictResponse? Predict(TicketPredictRequest request)
    {
        lock (_modelLock)
        {
            if (_predictionEngine is null)
                return null;

            var ticketData = new TicketData
            {
                Subject = request.Subject,
                Description = request.Description,
                Priority = request.Priority,
            };

            var prediction = _predictionEngine.Predict(ticketData);

            var confidence = new Dictionary<string, float>();
            for (var i = 0; i < prediction.Score.Length && i < _categoryLabels.Length; i++)
            {
                confidence[_categoryLabels[i]] = prediction.Score[i];
            }

            return new PredictResponse
            {
                PredictedCategory = prediction.Category,
                Confidence = confidence,
            };
        }
    }

    public bool IsModelTrained
    {
        get { lock (_modelLock) { return _model is not null; } }
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketsController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    /// <summary>
    /// Trains the ML model and returns evaluation metrics.
    /// </summary>
    [HttpPost("train")]
    public ActionResult<EvaluationResponse> Train()
    {
        var evaluation = _classifier.TrainAndEvaluate();
        return Ok(evaluation);
    }

    /// <summary>
    /// Predicts the category for a support ticket.
    /// </summary>
    [HttpPost("predict")]
    public ActionResult<PredictResponse> Predict([FromBody] TicketPredictRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest(new { error = "Subject or Description is required." });

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest(new { error = "Priority must be between 1 and 3." });

        if (!_classifier.IsModelTrained)
            return BadRequest(new { error = "Model has not been trained yet. Call POST /api/tickets/train first." });

        var result = _classifier.Predict(request);
        return Ok(result);
    }
}

